// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000009
int dp[5005][205][205];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A, B;
        scanf("%d %d %d", &N, &A, &B);
        int S[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &S[i]);
        }
        // Initialize DP array
        for (int i = 0; i <= N; i++) {
            for (int a = 0; a <= A; a++) {
                for (int b = 0; b <= B; b++) {
                    dp[i][a][b] = 0;
                }
            }
        }
        dp[0][0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int a = 0; a <= A; a++) {
                for (int b = 0; b <= B; b++) {
                    // Not including the current element
                    dp[i][a][b] = dp[i - 1][a][b];
                    // Including the current element
                    if (i > 1) {
                        if (S[i - 1] < S[i - 2] && S[i - 1] > S[i]) {
                            dp[i][a][b] = (dp[i][a][b] + dp[i - 1][a - 1][b]) % MOD;
                        } else if (S[i - 1] > S[i - 2] && S[i - 1] < S[i]) {
                            dp[i][a][b] = (dp[i][a][b] + dp[i - 1][a][b - 1]) % MOD;
                        }
                    }
                }
            }
        }
        printf("%d\n", dp[N][A][B]);
    }
    return 0;
}

